// Calculate previous date and vault paths
const currentDate = $json.currentDate;
const vaultPath = $json.vaultPath || 'C:\\Users\\aryan\\OneDrive\\Documents\\Obsidian Vault';
const digestDir = vaultPath + '\\Email Digests';

// Calculate previous date
const parts = currentDate.split('-');
const today = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
const yesterday = new Date(today);
yesterday.setDate(yesterday.getDate() - 1);
const previousDate = yesterday.toISOString().split('T')[0];

return [{
  json: {
    currentDate,
    previousDate,
    vaultPath,
    digestDir,
    actionItemsPath: digestDir + '\\action-items.md',
    ongoingThreadsPath: digestDir + '\\ongoing-threads.md',
    previousDigestPath: digestDir + '\\' + previousDate + '.md',
    lastRunPath: digestDir + '\\.last-run.txt'
  }
}];

// Parse all context files and build output
const calcPaths = $('Calculate Paths').first().json;

// Parse last run timestamp
let lastRunTimestamp;
try {
  const lastRunData = $('Read Last Run').first();
  if (lastRunData && lastRunData.json && lastRunData.json.data) {
    lastRunTimestamp = lastRunData.json.data.toString().trim();
  } else if (lastRunData && lastRunData.binary) {
    // Binary file read
    const buf = Buffer.from(lastRunData.binary.data.data, 'base64');
    lastRunTimestamp = buf.toString('utf8').trim();
  }
} catch (e) {}

// Fallback: 18 hours ago
if (!lastRunTimestamp || lastRunTimestamp.length < 10) {
  const fallback = new Date(Date.now() - 18 * 60 * 60 * 1000);
  lastRunTimestamp = fallback.toISOString();
}

// Parse action items
let previousActionItems = [];
try {
  const actionData = $('Read Action Items').first();
  let actionContent = '';
  if (actionData && actionData.json && actionData.json.data) {
    actionContent = actionData.json.data.toString();
  }

  if (actionContent) {
    const lines = actionContent.split('\n');
    let currentPriority = 'when-possible';

    for (const line of lines) {
      if (line.includes('Must Do Today')) currentPriority = 'must-do-today';
      else if (line.includes('This Week')) currentPriority = 'this-week';
      else if (line.includes('When Possible')) currentPriority = 'when-possible';
      else if (line.includes('Completed')) currentPriority = 'completed';

      const checkboxMatch = line.match(/^- \[ \] (.+?)(?:\s*—\s*Deadline:\s*(.+?))?(?:\s*—\s*Source:\s*(.+?))?(?:\s*\(added\s*(.+?)\))?$/);
      if (checkboxMatch && currentPriority !== 'completed') {
        previousActionItems.push({
          task: checkboxMatch[1].trim(),
          deadline: checkboxMatch[2] ? checkboxMatch[2].trim() : null,
          source: checkboxMatch[3] ? checkboxMatch[3].trim() : null,
          addedDate: checkboxMatch[4] ? checkboxMatch[4].trim() : calcPaths.previousDate,
          priority: currentPriority
        });
      }
    }
  }
} catch (e) {}

// Parse previous digest summary and email count
let previousDigestSummary = '';
let previousEmailCount = 0;
try {
  const digestData = $('Read Previous Digest').first();
  let digestContent = '';
  if (digestData && digestData.json && digestData.json.data) {
    digestContent = digestData.json.data.toString();
  }

  if (digestContent) {
    // Extract YAML frontmatter email count
    const emailCountMatch = digestContent.match(/total_emails:\s*(\d+)/);
    if (emailCountMatch) previousEmailCount = parseInt(emailCountMatch[1]);

    // Extract executive summary section
    const summaryMatch = digestContent.match(/## Executive Summary\n\n([\s\S]*?)\n\n---/);
    if (summaryMatch) previousDigestSummary = summaryMatch[1].trim();
  }
} catch (e) {}

// Parse ongoing threads
let ongoingThreads = [];
try {
  const threadData = $('Read Ongoing Threads').first();
  let threadContent = '';
  if (threadData && threadData.json && threadData.json.data) {
    threadContent = threadData.json.data.toString();
  }

  if (threadContent) {
    const threadBlocks = threadContent.split(/### /).filter(b => b.trim());
    for (const block of threadBlocks) {
      const lines = block.split('\n').filter(l => l.trim());
      if (lines.length > 0 && !lines[0].startsWith('Ongoing') && !lines[0].startsWith('Archived')) {
        const subjectMatch = lines[0].match(/(.+?)\s*(?:\((.+?)\))?$/);
        if (subjectMatch) {
          ongoingThreads.push({
            subject: subjectMatch[1].trim(),
            threadId: subjectMatch[2] || '',
            participants: [],
            lastActivity: '',
            summary: lines.slice(1).join(' ').trim()
          });
        }
      }
    }
  }
} catch (e) {}

return [{
  json: {
    lastRunTimestamp,
    previousActionItems,
    previousDigestSummary,
    previousEmailCount,
    ongoingThreads,
    currentDate: calcPaths.currentDate,
    previousDate: calcPaths.previousDate
  }
}];
